// Generated by generate.ts — hidden adversarial suite for prime-factorize.
// Run via `npx tsx __audit__/primeFactorize.hidden.ts` inside the scratch project.
import { primeFactorize } from '../src/primeFactorize'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("n below 2 empty", primeFactorize(1), [])
await check("zero empty", primeFactorize(0), [])
await check("classic 12", primeFactorize(12), [2,2,3])
await check("prime stays itself", primeFactorize(17), [17])
await check("highly composite 360", primeFactorize(360), [2,2,2,3,3,5])
await check("square of large prime", primeFactorize(9409), [97,97])
await check("power of two", primeFactorize(64), [2,2,2,2,2,2])
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
